function transform (message, context) {

  //Copy forward all of our message content
  const contextBannerId = message.payload.bannerId;
  const bannerId = contextBannerId;
  const contextPidm = message.payload.bannerPidm;
  const bannerPidm = contextPidm;
  const contextPersons = message.payload.persons;
  const persons = contextPersons[0]; //only getting one person, so move it down a level in the heirarchy

  const bannerGuid = persons.id;

  return { payload:
    {
      bannerPidm,
      bannerId,
      bannerGuid,
      persons
    }
  }
}
